namespace rime {

Config::Config() : ConfigItemRef(nullptr), data_(New<ConfigData>()) {
  ConfigItemRef::data_ = data_.get();
}

Config::~Config() {}

Config::Config(an<ConfigData> data) : ConfigItemRef(data.get()), data_(data) {}

bool Config::Save() {
  return data_->Save();
}

