49	  if (!stream.good()) {
50	    LOG(ERROR) << "failed to save config to stream.";
51	    return false;
52	  }
53	  try {
54	    YAML::Emitter emitter(stream);
55	    EmitYaml(root, &emitter, 0);
56	  } catch (YAML::Exception& e) {
57	    LOG(ERROR) << "Error emitting YAML: " << e.what();
58	    return false;
59	  }
60	  return true;
61	}
