84	bool ConfigData::SaveToFile(const path& file_path) {
85	  // update status
86	  file_path_ = file_path;
87	  modified_ = false;
88	  if (file_path.empty()) {
89	    // not really saving
90	    return false;
91	  }
92	  LOG(INFO) << "saving config file '" << file_path << "'.";
93	  // dump tree
94	  std::ofstream out(file_path.c_str());
95	  return SaveToStream(out);
96	}
97	
98	bool ConfigData::IsListItemReference(const string& key) {
99	  return key.length() > 1 && key[0] == '@' && std::isalnum(key[1]);
100	}
101	
102	string ConfigData::FormatListIndex(size_t index) {
103	  std::ostringstream formatted;
104	  formatted << "@" << index;
105	  return formatted.str();
106	}
107	
108	static const string kAfter("after");
109	static const string kBefore("before");
110	static const string kLast("last");
111	static const string kNext("next");
112	
113	size_t ConfigData::ResolveListIndex(an<ConfigItem> item,
114	                                    const string& key,
115	                                    bool read_only) {
116	  if (!IsListItemReference(key)) {
117	    return 0;
118	  }
119	  an<ConfigList> list = As<ConfigList>(item);
120	  if (!list) {
121	    return 0;
122	  }
123	  size_t cursor = 1;
124	  unsigned int index = 0;
125	  bool will_insert = false;
126	  if (key.compare(cursor, kNext.length(), kNext) == 0) {
127	    cursor += kNext.length();
128	    index = list->size();
129	  } else if (key.compare(cursor, kBefore.length(), kBefore) == 0) {
130	    cursor += kBefore.length();
131	    will_insert = true;
132	  } else if (key.compare(cursor, kAfter.length(), kAfter) == 0) {
133	    cursor += kAfter.length();
134	    index += 1;  // after i == before i+1
135	    will_insert = true;
136	  }
137	  if (cursor < key.length() && key[cursor] == ' ') {
138	    ++cursor;
139	  }
140	  if (key.compare(cursor, kLast.length(), kLast) == 0) {
141	    cursor += kLast.length();
142	    index += list->size();
143	    if (index != 0) {  // when list is empty, (before|after) last == 0
144	      --index;
145	    }
146	  } else {
147	    index += std::strtoul(key.c_str() + cursor, NULL, 10);
148	  }
149	  if (will_insert && !read_only) {
150	    list->Insert(index, nullptr);
151	  }
152	  return index;
153	}
154	
155	class ConfigDataRootRef : public ConfigItemRef {
156	 public:
157	  ConfigDataRootRef(ConfigData* data) : ConfigItemRef(nullptr), data_(data) {}
158	  an<ConfigItem> GetItem() const override { return data_->root; }
159	  void SetItem(an<ConfigItem> item) override { data_->root = item; }
160	
161	 private:
162	  ConfigData* data_;
163	};
164	
165	an<ConfigItemRef> TypeCheckedCopyOnWrite(an<ConfigItemRef> parent,
166	                                         const string& key) {
167	  // special case to allow editing current node by __append: __merge: /+: /=:
168	  if (key.empty()) {
169	    return parent;
170	  }
171	  bool is_list = ConfigData::IsListItemReference(key);
172	  auto expected_node_type = is_list ? ConfigItem::kList : ConfigItem::kMap;
173	  an<ConfigItem> existing_node = *parent;
174	  if (existing_node && existing_node->type() != expected_node_type) {
175	    LOG(ERROR) << "copy on write failed; incompatible node type: " << key;
176	    return nullptr;
177	  }
178	  return Cow(parent, key);
179	}
180	
181	an<ConfigItemRef> TraverseCopyOnWrite(an<ConfigItemRef> head,
182	                                      const string& node_path) {
183	  DLOG(INFO) << "TraverseCopyOnWrite(" << node_path << ")";
184	  if (node_path.empty() || node_path == "/") {
185	    return head;
186	  }
187	  vector<string> keys = ConfigData::SplitPath(node_path);
188	  size_t n = keys.size();
189	  for (size_t i = 0; i < n; ++i) {
190	    const auto& key = keys[i];
191	    if (auto child = TypeCheckedCopyOnWrite(head, key)) {
192	      head = child;
193	    } else {
194	      LOG(ERROR) << "while writing to " << node_path;
195	      return nullptr;
196	    }
197	  }
198	  return head;
199	}
200	
201	bool ConfigData::TraverseWrite(const string& node_path, an<ConfigItem> item) {
202	  LOG(INFO) << "write: " << node_path;
203	  auto root = New<ConfigDataRootRef>(this);
204	  if (auto target = TraverseCopyOnWrite(root, node_path)) {
205	    *target = item;
206	    set_modified();
207	    return true;
208	  } else {
209	    return false;
210	  }
211	}
212	
213	vector<string> ConfigData::SplitPath(const string& node_path) {
214	  vector<string> keys;
215	  auto is_separator = boost::is_any_of("/");
216	  auto trimmed_path = boost::trim_left_copy_if(node_path, is_separator);
217	  boost::split(keys, trimmed_path, is_separator);
218	  return keys;
219	}
220	
221	string ConfigData::JoinPath(const vector<string>& keys) {
222	  return boost::join(keys, "/");
223	}
224	
225	an<ConfigItem> ConfigData::Traverse(const string& node_path) {
226	  DLOG(INFO) << "traverse: " << node_path;
227	  if (node_path.empty() || node_path == "/") {
228	    return root;
229	  }
230	  vector<string> keys = SplitPath(node_path);
231	  // find the YAML::Node, and wrap it!
232	  an<ConfigItem> p = root;
233	  for (auto it = keys.begin(), end = keys.end(); it != end; ++it) {
234	    ConfigItem::ValueType node_type = ConfigItem::kMap;
235	    size_t list_index = 0;
236	    if (IsListItemReference(*it)) {
237	      node_type = ConfigItem::kList;
238	      list_index = ResolveListIndex(p, *it, true);
239	    }
240	    if (!p || p->type() != node_type) {
241	      return nullptr;
242	    }
243	    if (node_type == ConfigItem::kList) {
244	      p = As<ConfigList>(p)->GetAt(list_index);
245	    } else {
246	      p = As<ConfigMap>(p)->Get(*it);
247	    }
248	  }
249	  return p;
250	}
251	
252	an<ConfigItem> ConvertFromYaml(const YAML::Node& node,
253	                               ConfigCompiler* compiler) {
254	  if (YAML::NodeType::Null == node.Type()) {
255	    return nullptr;
256	  }
257	  if (YAML::NodeType::Scalar == node.Type()) {
258	    return New<ConfigValue>(node.as<string>());
259	  }
260	  if (YAML::NodeType::Sequence == node.Type()) {
261	    auto config_list = New<ConfigList>();
262	    for (auto it = node.begin(), end = node.end(); it != end; ++it) {
263	      if (compiler) {
264	        compiler->Push(config_list, config_list->size());
265	      }
266	      config_list->Append(ConvertFromYaml(*it, compiler));
267	      if (compiler) {
268	        compiler->Pop();
269	      }
270	    }
271	    return config_list;
272	  } else if (YAML::NodeType::Map == node.Type()) {
273	    auto config_map = New<ConfigMap>();
274	    for (auto it = node.begin(), end = node.end(); it != end; ++it) {
275	      string key = it->first.as<string>();
276	      if (compiler) {
277	        compiler->Push(config_map, key);
278	      }
279	      auto value = ConvertFromYaml(it->second, compiler);
280	      if (compiler) {
281	        compiler->Pop();
282	      }
283	      if (!compiler || !compiler->Parse(key, value)) {
284	        config_map->Set(key, value);
285	      }
286	    }
287	    return config_map;
288	  }
289	  return nullptr;
290	}
291	
292	void EmitScalar(const string& str_value, YAML::Emitter* emitter) {
293	  if (str_value.find_first_of("\r\n") != string::npos) {
294	    *emitter << YAML::Literal;
295	  } else if (!std::all_of(str_value.cbegin(), str_value.cend(), [](auto ch) {
296	               return std::isalnum(ch) || ch == '_' || ch == '.';
297	             })) {
298	    *emitter << YAML::DoubleQuoted;
299	  }
300	  *emitter << str_value;
301	}
302	
303	void EmitYaml(an<ConfigItem> node, YAML::Emitter* emitter, int depth) {
304	  if (!node || !emitter)
305	    return;
306	  if (node->type() == ConfigItem::kScalar) {
307	    auto value = As<ConfigValue>(node);
308	    EmitScalar(value->str(), emitter);
309	  } else if (node->type() == ConfigItem::kList) {
310	    if (depth >= 3) {
311	      *emitter << YAML::Flow;
312	    }
313	    *emitter << YAML::BeginSeq;
314	    auto list = As<ConfigList>(node);
315	    for (auto it = list->begin(), end = list->end(); it != end; ++it) {
316	      EmitYaml(*it, emitter, depth + 1);
317	    }
318	    *emitter << YAML::EndSeq;
319	  } else if (node->type() == ConfigItem::kMap) {
320	    if (depth >= 3) {
321	      *emitter << YAML::Flow;
322	    }
