12	Schema::Schema() : schema_id_(".default") {
13	  config_.reset(Config::Require("config")->Create("default"));
14	  FetchUsefulConfigItems();
15	}
16	
17	Schema::Schema(const string& schema_id) : schema_id_(schema_id) {
18	  config_.reset(boost::starts_with(schema_id_, ".")
19	                    ? Config::Require("config")->Create(schema_id.substr(1))
20	                    : Config::Require("schema")->Create(schema_id));
21	  FetchUsefulConfigItems();
22	}
23	
24	void Schema::FetchUsefulConfigItems() {
25	  if (!config_) {
26	    schema_name_ = schema_id_ + "?";
27	    return;
